3	use App\Actions\Auth\PerformLogout;
4	use App\Livewire\Auth\ChangePasswordForm;
5	use App\Livewire\Auth\LoginForm;
6	use App\Livewire\Auth\RegisterForm;
7	use App\Livewire\Auth\StepUpVerification;
8	use App\Livewire\Catalog\CatalogList;
9	use App\Livewire\Catalog\ServiceDetail;
10	use App\Livewire\Catalog\ServiceManager;
11	use App\Livewire\Admin\ExportManager;
12	use App\Livewire\Admin\ImportManager;
13	use App\Livewire\Reservations\ReservationDashboard;
14	use App\Livewire\Reservations\TimeSlotManager;
15	use Illuminate\Support\Facades\Route;
16	
17	// Guest routes
18	Route::middleware('guest')->group(function () {
19	    Route::get('/login', LoginForm::class)->name('login');
20	    Route::get('/register', RegisterForm::class)->name('register');
21	});
22	
23	// Auth routes
24	Route::middleware('auth')->group(function () {
25	    // Logout
26	    Route::post('/logout', function (PerformLogout $action) {
27	        $action->execute(allDevices: true);
28	        return redirect()->route('login');
29	    })->name('logout');
30	
31	    // Password change (accessible even with expired password)
32	    Route::get('/password/change', ChangePasswordForm::class)->name('auth.password.change');
33	
34	    // Step-up verification
35	    Route::get('/auth/verify', StepUpVerification::class)->name('auth.step-up');
36	
37	    // Session keep-alive ping
38	    Route::post('/api/ping', function () {
39	        return response()->json(['status' => 'ok']);
40	    })->name('api.ping');
41	
42	    // Protected routes (require non-expired password)
43	    Route::middleware([\App\Http\Middleware\EnsurePasswordNotExpired::class])->group(function () {
44	        // Dashboard
45	        Route::get('/', function () {
46	            return view('dashboard');
47	        })->name('dashboard');
48	
49	        // Service Catalog
50	        Route::get('/catalog', CatalogList::class)->name('catalog');
51	        Route::get('/services/{service}', ServiceDetail::class)->name('services.show');
52	
53	        // Service Management (editor/admin only)
54	        Route::middleware('role:editor,admin')->group(function () {
55	            Route::get('/services-manage/create', ServiceManager::class)->name('services.create');
56	            Route::get('/services-manage/{serviceId}/edit', ServiceManager::class)->name('services.edit');
57	            Route::get('/services/{service}/time-slots', TimeSlotManager::class)->name('services.time-slots');
58	        });
59	
60	        // Reservations (learner)
61	        Route::get('/reservations', ReservationDashboard::class)->name('reservations');
62	
63	        // Admin routes
64	        Route::middleware('role:admin')->prefix('admin')->group(function () {
65	            Route::get('/import', ImportManager::class)->name('admin.import');
66	
67	            // Export requires step-up auth for sensitive data access
68	            Route::middleware('step-up')->group(function () {
69	                Route::get('/export', ExportManager::class)->name('admin.export');
70	            });
71	        });
72	    });
73	});
