5	use App\Enums\UserRole;
6	use App\Models\PasswordHistory;
7	use App\Models\User;
8	use App\Services\AuditService;
9	use App\Services\PasswordPolicyService;
10	use Illuminate\Support\Facades\Auth;
11	use Illuminate\Support\Facades\Hash;
12	use Livewire\Component;
13	
14	class RegisterForm extends Component
15	{
16	    public string $username = '';
17	    public string $name = '';
18	    public string $email = '';
19	    public string $password = '';
20	    public string $passwordConfirmation = '';
21	    public string $role = 'learner';
22	    public string $errorMessage = '';
23	    public array $policyErrors = [];
24	
25	    public function mount(): void
26	    {
27	        if (auth()->check()) {
28	            $this->redirect(route('dashboard'));
29	        }
30	    }
31	
32	    public function register(PasswordPolicyService $policy, AuditService $audit): void
33	    {
34	        $this->validate([
35	            'username' => 'required|string|min:3|max:100|alpha_dash|unique:users,username',
36	            'name' => 'required|string|min:2|max:255',
37	            'email' => 'required|email|max:255|unique:users,email',
38	            'password' => 'required|string|min:12',
39	            'passwordConfirmation' => 'required|same:password',
40	            'role' => 'required|in:learner,editor,admin',
41	        ]);
42	
43	        $this->errorMessage = '';
44	        $this->policyErrors = [];
45	
46	        // Validate password against policy
47	        $errors = $policy->validate($this->password);
48	        if (!empty($errors)) {
49	            $this->policyErrors = $errors;
50	            return;
51	        }
52	
53	        $hashedPassword = Hash::make($this->password);
54	
55	        $user = User::create([
56	            'username' => $this->username,
57	            'name' => $this->name,
58	            'email' => $this->email,
59	            'password' => $this->password,
60	            'role' => UserRole::from($this->role),
61	            'password_updated_at' => now(),
62	            'is_active' => true,
63	        ]);
64	
65	        PasswordHistory::create([
66	            'user_id' => $user->id,
67	            'password_hash' => $hashedPassword,
68	            'created_at' => now(),
69	        ]);
70	
71	        $audit->log(\App\Enums\AuditAction::Login, $user->id, [
72	            'action' => 'account_created',
73	            'role' => $this->role,
74	        ]);
75	
76	        Auth::login($user);
77	        session()->regenerate();
78	
79	        $this->redirect(route('dashboard'), navigate: true);
80	    }
81	
82	    public function render()
83	    {
84	        return view('livewire.auth.register-form')
85	            ->layout('components.layouts.guest', ['title' => 'Create Account']);
86	    }
87	}
