3	namespace App\Services;
4	
5	use App\Models\DataDictionary;
6	use App\Models\FormRule;
7	use Illuminate\Support\Collection;
8	use Illuminate\Support\Facades\Cache;
9	
10	class DataDictionaryService
11	{
12	    public function getByType(string $type): Collection
13	    {
14	        return Cache::remember("dict.{$type}", 300, function () use ($type) {
15	            return DataDictionary::ofType($type)->get();
16	        });
17	    }
18	
19	    public function getLabelsForType(string $type): array
20	    {
21	        return $this->getByType($type)->pluck('label', 'key')->toArray();
22	    }
23	
24	    public function isValidKey(string $type, string $key): bool
25	    {
26	        return $this->getByType($type)->contains('key', $key);
27	    }
28	
29	    public function getValidationRules(string $entity): array
30	    {
31	        $rules = FormRule::where('entity', $entity)
32	            ->where('is_active', true)
33	            ->get();
34	
35	        $laravelRules = [];
36	
37	        foreach ($rules as $rule) {
38	            $laravelRules[$rule->field] = $this->buildLaravelRule($rule->rules);
39	        }
40	
41	        return $laravelRules;
42	    }
43	
44	    private function buildLaravelRule(array $config): array
45	    {
46	        $rules = [];
47	
48	        if (!empty($config['required'])) {
49	            $rules[] = 'required';
50	        } else {
51	            $rules[] = 'nullable';
52	        }
53	
54	        if (isset($config['type'])) {
55	            $rules[] = $config['type']; // string, integer, numeric, etc.
56	        }
57	
58	        if (isset($config['min'])) {
59	            $rules[] = "min:{$config['min']}";
60	        }
61	
62	        if (isset($config['max'])) {
63	            $rules[] = "max:{$config['max']}";
64	        }
65	
66	        if (isset($config['regex'])) {
67	            $rules[] = "regex:{$config['regex']}";
68	        }
69	
70	        if (isset($config['in'])) {
71	            $rules[] = 'in:' . implode(',', $config['in']);
72	        }
73	
74	        return $rules;
75	    }
76	
77	    public function clearCache(string $type): void
78	    {
79	        Cache::forget("dict.{$type}");
80	    }
81	}
