1	<?php
2	
3	namespace App\Services;
4	
5	use App\Enums\AuditAction;
6	use App\Enums\ReservationStatus;
7	use App\Jobs\ExpireUnconfirmedReservation;
8	use App\Models\Penalty;
9	use App\Models\Reservation;
10	use App\Models\TimeSlot;
11	use App\Models\User;
12	use Illuminate\Support\Facades\DB;
13	
14	class ReservationService
15	{
16	    private const EXPIRY_MINUTES = 30;
17	    private const FREE_CANCEL_HOURS = 24;
18	    private const CANCEL_FEE = 25.00;
19	    private const CANCEL_POINTS = 50;
20	    private const NO_SHOW_THRESHOLD = 2;
21	    private const NO_SHOW_WINDOW_DAYS = 60;
22	    private const FREEZE_DAYS = 7;
23	
24	    public function __construct(private AuditService $audit) {}
25	
26	    public function createReservation(User $user, int $timeSlotId): Reservation
27	    {
28	        if ($user->isBookingFrozen()) {
29	            throw new \DomainException('Your booking privileges are frozen until ' . $user->booking_frozen_until->format('M d, Y'));
30	        }
31	
32	        return DB::transaction(function () use ($user, $timeSlotId) {
33	            // Pessimistic lock on the time slot
34	            $slot = TimeSlot::lockForUpdate()->findOrFail($timeSlotId);
35	
36	            if (!$slot->hasAvailability()) {
37	                throw new \DomainException('This time slot is no longer available.');
38	            }
39	
40	            if (!$slot->isFuture()) {
41	                throw new \DomainException('Cannot book a past time slot.');
42	            }
43	
44	            // Check for existing reservation on same slot
45	            $existing = Reservation::where('user_id', $user->id)
46	                ->where('time_slot_id', $timeSlotId)
47	                ->whereNotIn('status', [
48	                    ReservationStatus::Cancelled->value,
49	                    ReservationStatus::NoShow->value,
50	                ])
51	                ->exists();
52	
53	            if ($existing) {
54	                throw new \DomainException('You already have a reservation for this time slot.');
55	            }
56	
57	            $reservation = Reservation::create([
58	                'user_id' => $user->id,
59	                'service_id' => $slot->service_id,
60	                'time_slot_id' => $timeSlotId,
61	                'status' => ReservationStatus::Pending,
62	                'expires_at' => now()->addMinutes(self::EXPIRY_MINUTES),
63	            ]);
64	
65	            $slot->increment('booked_count');
66	
67	            // Dispatch expiry job
68	            ExpireUnconfirmedReservation::dispatch($reservation->id)
69	                ->delay(now()->addMinutes(self::EXPIRY_MINUTES));
70	
71	            $this->audit->log(AuditAction::PolicyEdit, $user->id, [
72	                'action' => 'reservation_created',
73	                'reservation_id' => $reservation->id,
74	                'time_slot_id' => $timeSlotId,
75	            ]);
76	
77	            return $reservation;
78	        });
79	    }
80	
81	    public function confirm(Reservation $reservation): Reservation
82	    {
83	        if ($reservation->status !== ReservationStatus::Pending) {
84	            throw new \DomainException('Only pending reservations can be confirmed.');
85	        }
86	
87	        if ($reservation->expires_at && $reservation->expires_at->isPast()) {
88	            throw new \DomainException('This reservation has expired.');
89	        }
90	
91	        $reservation->update([
92	            'status' => ReservationStatus::Confirmed,
93	            'confirmed_at' => now(),
94	            'expires_at' => null,
95	        ]);
96	
97	        $this->audit->log(AuditAction::PolicyEdit, $reservation->user_id, [
98	            'action' => 'reservation_confirmed',
99	            'reservation_id' => $reservation->id,
100	        ]);
101	
102	        return $reservation;
103	    }
104	
105	    public function cancel(Reservation $reservation, ?string $reason = null): Reservation
106	    {
107	        if (!$reservation->canCancel()) {
108	            throw new \DomainException('This reservation cannot be cancelled.');
109	        }
110	
111	        return DB::transaction(function () use ($reservation, $reason) {
112	            $reservation->update([
113	                'status' => ReservationStatus::Cancelled,
114	                'cancelled_at' => now(),
115	                'cancellation_reason' => $reason,
116	            ]);
117	
118	            // Release the slot
119	            $reservation->timeSlot->decrement('booked_count');
120	
121	            // Apply late cancellation penalty
122	            if (!$reservation->isFreeCancellation()) {
123	                Penalty::create([
124	                    'user_id' => $reservation->user_id,
125	                    'reservation_id' => $reservation->id,
126	                    'type' => 'late_cancellation',
127	                    'fee_amount' => self::CANCEL_FEE,
128	                    'points_deducted' => self::CANCEL_POINTS,
129	                    'reason' => 'Cancelled less than 24 hours before start time.',
130	                    'created_at' => now(),
131	                ]);
132	            }
133	
134	            $this->audit->log(AuditAction::PolicyEdit, $reservation->user_id, [
135	                'action' => 'reservation_cancelled',
136	                'reservation_id' => $reservation->id,
137	                'free_cancellation' => $reservation->isFreeCancellation(),
138	            ]);
139	
140	            return $reservation;
141	        });
142	    }
143	
144	    public function reschedule(Reservation $reservation, int $newTimeSlotId): Reservation
145	    {
146	        if (!$reservation->canCancel()) {
147	            throw new \DomainException('This reservation cannot be rescheduled.');
148	        }
149	
150	        return DB::transaction(function () use ($reservation, $newTimeSlotId) {
151	            // Cancel old reservation (no penalty for reschedule)
152	            $reservation->update([
153	                'status' => ReservationStatus::Cancelled,
154	                'cancelled_at' => now(),
155	                'cancellation_reason' => 'Rescheduled',
156	            ]);
157	            $reservation->timeSlot->decrement('booked_count');
158	
159	            // Create new reservation
160	            return $this->createReservation($reservation->user, $newTimeSlotId);
161	        });
162	    }
163	
164	    public function checkIn(Reservation $reservation): Reservation
165	    {
166	        if (!$reservation->canCheckIn()) {
167	            throw new \DomainException('Check-in is not available at this time.');
168	        }
169	
170	        $isLate = $reservation->timeSlot->isLateArrival();
171	
172	        $reservation->update([
173	            'status' => $isLate
174	                ? ReservationStatus::PartialAttendance
175	                : ReservationStatus::CheckedIn,
176	            'checked_in_at' => now(),
177	        ]);
178	
179	        $this->audit->log(AuditAction::PolicyEdit, $reservation->user_id, [
