5	use App\Models\PasswordHistory;
6	use App\Models\User;
7	use Illuminate\Support\Facades\Hash;
8	
9	class PasswordPolicyService
10	{
11	    public const MIN_LENGTH = 12;
12	    public const HISTORY_COUNT = 5;
13	    public const ROTATION_DAYS = 90;
14	
15	    public function validate(string $password, ?User $user = null): array
16	    {
17	        $errors = [];
18	
19	        if (strlen($password) < self::MIN_LENGTH) {
20	            $errors[] = 'Password must be at least ' . self::MIN_LENGTH . ' characters.';
21	        }
22	
23	        if (!preg_match('/[A-Z]/', $password)) {
24	            $errors[] = 'Password must contain at least one uppercase letter.';
25	        }
26	
27	        if (!preg_match('/[a-z]/', $password)) {
28	            $errors[] = 'Password must contain at least one lowercase letter.';
29	        }
30	
31	        if (!preg_match('/[0-9]/', $password)) {
32	            $errors[] = 'Password must contain at least one number.';
33	        }
34	
35	        if (!preg_match('/[^A-Za-z0-9]/', $password)) {
36	            $errors[] = 'Password must contain at least one special character.';
37	        }
38	
39	        if ($user !== null && $this->matchesPreviousPasswords($password, $user)) {
40	            $errors[] = 'Password cannot match any of your last ' . self::HISTORY_COUNT . ' passwords.';
41	        }
42	
43	        return $errors;
44	    }
45	
46	    public function recordPassword(User $user, string $hashedPassword): void
47	    {
48	        PasswordHistory::create([
49	            'user_id' => $user->id,
50	            'password_hash' => $hashedPassword,
51	            'created_at' => now(),
52	        ]);
53	
54	        // Keep only the last HISTORY_COUNT entries
55	        $toDelete = PasswordHistory::where('user_id', $user->id)
56	            ->orderByDesc('created_at')
57	            ->skip(self::HISTORY_COUNT)
58	            ->pluck('id');
59	
60	        if ($toDelete->isNotEmpty()) {
61	            PasswordHistory::whereIn('id', $toDelete)->delete();
62	        }
63	    }
64	
65	    private function matchesPreviousPasswords(string $password, User $user): bool
66	    {
67	        $histories = PasswordHistory::where('user_id', $user->id)
68	            ->orderByDesc('created_at')
69	            ->limit(self::HISTORY_COUNT)
70	            ->pluck('password_hash');
71	
72	        foreach ($histories as $hash) {
73	            if (Hash::check($password, $hash)) {
74	                return true;
75	            }
76	        }
77	
78	        return false;
79	    }
80	}
