137	    private function detectServiceDuplicates(array $row, array $fieldMapping): Collection
138	    {
139	        $conflicts = collect();
140	        $mappedTitle = $this->getMappedValue($row, $fieldMapping, 'title');
141	
142	        if ($mappedTitle === null) {
143	            return $conflicts;
144	        }
145	
146	        $normalizedTitle = $this->normalizeTitle($mappedTitle);
147	
148	        // Exact ID match
149	        $mappedId = $this->getMappedValue($row, $fieldMapping, 'id');
150	        if ($mappedId !== null) {
151	            $existing = Service::find($mappedId);
152	            if ($existing) {
153	                $conflicts->push([
154	                    'existing_id' => $existing->id,
155	                    'existing_data' => $existing->toArray(),
156	                    'similarity_score' => 1.0,
157	                    'match_type' => 'exact_id',
158	                ]);
159	                return $conflicts;
160	            }
161	        }
162	
163	        // Trigram similarity on normalized title
164	        $similar = DB::select(
165	            "SELECT id, title, similarity(lower(title), ?) as score
166	             FROM services
167	             WHERE similarity(lower(title), ?) >= ?
168	             ORDER BY score DESC
169	             LIMIT 5",
170	            [$normalizedTitle, $normalizedTitle, self::SIMILARITY_THRESHOLD]
171	        );
172	
173	        foreach ($similar as $match) {
174	            $existing = Service::find($match->id);
175	            if ($existing) {
176	                $conflicts->push([
177	                    'existing_id' => $existing->id,
178	                    'existing_data' => $existing->toArray(),
179	                    'similarity_score' => round((float) $match->score, 4),
180	                    'match_type' => 'title_similarity',
181	                ]);
182	            }
183	        }
184	
185	        return $conflicts;
186	    }
