namespace App\Livewire\Admin;

use App\Enums\AuditAction;
use App\Enums\UserRole;
use App\Http\Middleware\StepUpAuth;
use App\Models\User;
use App\Services\AuditService;
use Livewire\Component;
use Livewire\WithPagination;

class UserManager extends Component
{
    use WithPagination;

    public string $search = '';
    public string $roleFilter = '';
    public string $errorMessage = '';
    public string $successMessage = '';

    public function updatingSearch(): void
    {
        $this->resetPage();
    }

    public function changeRole(int $userId, string $newRole, AuditService $audit): void
    {
        $this->clearMessages();

        if (!StepUpAuth::isElevated()) {
            session(['step_up_redirect' => route('admin.users')]);
            $this->redirect(route('auth.step-up'));
            return;
        }

        $user = User::findOrFail($userId);
        $oldRole = $user->role->value;

        if ($oldRole === $newRole) {
            return;
        }

        $user->update(['role' => UserRole::from($newRole)]);

        $audit->log(AuditAction::RoleChange, auth()->id(), [
            'target_user_id' => $userId,
            'old_role' => $oldRole,
            'new_role' => $newRole,
        ], 'critical');

        $this->successMessage = "Role for {$user->name} changed from {$oldRole} to {$newRole}.";
    }

    public function deleteAccount(int $userId, AuditService $audit): void
    {
        $this->clearMessages();

        if (!StepUpAuth::isElevated()) {
            session(['step_up_redirect' => route('admin.users')]);
            $this->redirect(route('auth.step-up'));
            return;
        }

        if ($userId === auth()->id()) {
            $this->errorMessage = 'You cannot delete your own account.';
            return;
        }

        $user = User::findOrFail($userId);

        $audit->log(AuditAction::AccountDeleted, auth()->id(), [
            'deleted_user_id' => $userId,
            'deleted_username' => $user->username,
            'deleted_role' => $user->role->value,
        ], 'critical');

        $user->update(['is_active' => false]);

        $this->successMessage = "Account for {$user->name} has been deactivated.";
    }

    private function clearMessages(): void
    {
        $this->errorMessage = '';
        $this->successMessage = '';
    }

    public function render()
    {
        $query = User::query()->orderBy('name');

        if ($this->search) {
            $query->where(function ($q) {
                $q->where('name', 'ilike', "%{$this->search}%")
                  ->orWhere('username', 'ilike', "%{$this->search}%")
                  ->orWhere('email', 'ilike', "%{$this->search}%");
            });
        }

        if ($this->roleFilter) {
            $query->where('role', $this->roleFilter);
        }

        return view('livewire.admin.user-manager', [
            'users' => $query->paginate(15),
            'roles' => UserRole::cases(),
        ])->layout('components.layouts.app', ['title' => 'User Management']);
    }
}
"}

