namespace App\Http\Controllers\Api;

use App\Enums\AuditAction;
use App\Http\Controllers\Controller;
use App\Http\Resources\UserResource;
use App\Services\AuditService;
use Illuminate\Http\JsonResponse;
use Illuminate\Http\Request;
use Illuminate\Support\Facades\Auth;
use Illuminate\Support\Facades\Hash;

class AuthController extends Controller
{
    public function login(Request $request, AuditService $audit): JsonResponse
    {
        $request->validate([
            'username' => 'required|string',
            'password' => 'required|string',
        ]);

        if (!Auth::attempt(['username' => $request->username, 'password' => $request->password])) {
            $audit->log(AuditAction::LoginFailed, null, [
                'username' => $request->username,
            ], 'warning');

            return response()->json(['error' => 'Invalid credentials.'], 401);
        }

        $user = Auth::user();

        $audit->log(AuditAction::Login, $user->id);

        $token = $user->createToken('api-token')->plainTextToken;

        return response()->json([
            'token' => $token,
            'user' => new UserResource($user),
        ]);
    }

    public function me(Request $request): UserResource
    {
        return new UserResource($request->user());
    }

    public function logout(Request $request, AuditService $audit): JsonResponse
    {
        $audit->log(AuditAction::Logout, $request->user()->id);

        $request->user()->currentAccessToken()->delete();

        return response()->json(['message' => 'Logged out.']);
    }

    public function stepUpVerify(Request $request, AuditService $audit): JsonResponse
    {
        $request->validate([
            'password' => 'required|string',
        ]);

        $user = $request->user();

        if (!Hash::check($request->password, $user->password)) {
            $audit->log(AuditAction::StepUpFailed, $user->id, [], 'warning');
            return response()->json(['error' => 'Invalid password.'], 403);
        }

        $audit->log(AuditAction::StepUpVerified, $user->id);

        session(['step_up_verified_at' => now()]);

        return response()->json(['message' => 'Step-up verified.', 'elevated_until' => now()->addMinutes(5)->toIso8601String()]);
    }
}
"}

