            $dict = DataDictionary::findOrFail($this->editingDictId);
            $dict->update($data);
            $action = 'updated';
        } else {
            $dict = DataDictionary::create($data);
            $action = 'created';
        }

        $dictService->clearCache($this->dictType);

        $audit->log(AuditAction::DictionaryModified, auth()->id(), [
            'dictionary_id' => $dict->id,
            'action' => $action,
            'type' => $this->dictType,
            'key' => $this->dictKey,
        ]);

        $this->successMessage = "Dictionary entry {$action} successfully.";
        $this->showDictForm = false;
        $this->resetDictForm();
    }

    public function deleteDictionary(int $id, AuditService $audit, DataDictionaryService $dictService): void
    {
        $this->clearMessages();
        $dict = DataDictionary::findOrFail($id);
        $type = $dict->type;

        $audit->log(AuditAction::DictionaryModified, auth()->id(), [
            'dictionary_id' => $id,
            'action' => 'deleted',
            'type' => $dict->type,
            'key' => $dict->key,
        ]);

        $dict->delete();
        $dictService->clearCache($type);

        $this->successMessage = 'Dictionary entry deleted.';
    }

    public function openRuleForm(?int $id = null): void
    {
        $this->resetRuleForm();
        if ($id) {
            $rule = FormRule::findOrFail($id);
            $this->editingRuleId = $id;
            $this->ruleEntity = $rule->entity;
            $this->ruleField = $rule->field;
            $this->ruleRequired = !empty($rule->rules['required']);
            $this->ruleType = $rule->rules['type'] ?? 'string';
            $this->ruleMin = (string) ($rule->rules['min'] ?? '');
            $this->ruleMax = (string) ($rule->rules['max'] ?? '');
            $this->ruleRegex = $rule->rules['regex'] ?? '';
            $this->ruleIsActive = $rule->is_active;
        }
        $this->showRuleForm = true;
    }

    public function saveFormRule(AuditService $audit): void
    {
        $this->clearMessages();

        $this->validate([
            'ruleEntity' => 'required|string|max:100',
            'ruleField' => 'required|string|max:100',
            'ruleType' => 'required|string|in:string,integer,numeric,email,date,boolean',
        ]);

        $rules = ['type' => $this->ruleType];
        if ($this->ruleRequired) {
            $rules['required'] = true;
        }
        if ($this->ruleMin !== '') {
            $rules['min'] = (int) $this->ruleMin;
        }
        if ($this->ruleMax !== '') {
            $rules['max'] = (int) $this->ruleMax;
        }
        if ($this->ruleRegex !== '') {
            $rules['regex'] = $this->ruleRegex;
        }

        $data = [
            'entity' => $this->ruleEntity,
            'field' => $this->ruleField,
            'rules' => $rules,
            'is_active' => $this->ruleIsActive,
        ];

        if ($this->editingRuleId) {
            $formRule = FormRule::findOrFail($this->editingRuleId);
            $formRule->update($data);
            $action = 'updated';
        } else {
            $formRule = FormRule::create($data);
            $action = 'created';
        }

        $audit->log(AuditAction::FormRuleModified, auth()->id(), [
            'form_rule_id' => $formRule->id,
            'action' => $action,
            'entity' => $this->ruleEntity,
            'field' => $this->ruleField,
        ]);

        $this->successMessage = "Form rule {$action} successfully.";
        $this->showRuleForm = false;
        $this->resetRuleForm();
    }

    public function deleteFormRule(int $id, AuditService $audit): void
    {
        $this->clearMessages();
        $rule = FormRule::findOrFail($id);

        $audit->log(AuditAction::FormRuleModified, auth()->id(), [
            'form_rule_id' => $id,
            'action' => 'deleted',
            'entity' => $rule->entity,
            'field' => $rule->field,
        ]);

        $rule->delete();
        $this->successMessage = 'Form rule deleted.';
    }

    private function resetDictForm(): void
    {
        $this->editingDictId = null;
        $this->dictType = '';
        $this->dictKey = '';
        $this->dictLabel = '';
        $this->dictSortOrder = 0;
        $this->dictIsActive = true;
    }

    private function resetRuleForm(): void
    {
        $this->editingRuleId = null;
        $this->ruleEntity = '';
        $this->ruleField = '';
        $this->ruleRequired = false;
        $this->ruleType = 'string';
        $this->ruleMin = '';
        $this->ruleMax = '';
        $this->ruleRegex = '';
        $this->ruleIsActive = true;
    }

    private function clearMessages(): void
    {
        $this->errorMessage = '';
        $this->successMessage = '';
    }

    public function render()
    {
        $dictionaries = DataDictionary::orderBy('type')->orderBy('sort_order')->paginate(15, ['*'], 'dictPage');
        $formRules = FormRule::orderBy('entity')->orderBy('field')->paginate(15, ['*'], 'rulePage');

        return view('livewire.admin.dictionary-manager', [
            'dictionaries' => $dictionaries,
            'formRules' => $formRules,
        ])->layout('components.layouts.app', ['title' => 'Dictionary & Form Rules']);
    }
}
"}

