    {
        $this->clearMessages();
        $reservation = Reservation::where('user_id', auth()->id())
            ->with('service')
            ->findOrFail($reservationId);

        if (!$reservation->canCancel()) {
            $this->errorMessage = 'This reservation cannot be rescheduled.';
            return;
        }

        $this->reschedulingReservationId = $reservationId;
        $this->selectedNewSlotId = null;

        // Load available time slots for the same service
        $this->availableSlots = TimeSlot::where('service_id', $reservation->service_id)
            ->where('id', '!=', $reservation->time_slot_id)
            ->available()
            ->orderBy('start_time')
            ->limit(20)
            ->get()
            ->map(fn ($slot) => [
                'id' => $slot->id,
                'label' => $slot->start_time->format('D, M d, Y g:i A') . ' - ' . $slot->end_time->format('g:i A'),
                'available' => $slot->capacity - $slot->booked_count,
            ])
            ->toArray();

        if (empty($this->availableSlots)) {
            $this->errorMessage = 'No other time slots are available for this service.';
            $this->reschedulingReservationId = null;
        }
    }

    public function cancelReschedule(): void
    {
        $this->reschedulingReservationId = null;
        $this->selectedNewSlotId = null;
        $this->availableSlots = [];
    }

    public function confirmReschedule(ReservationService $service): void
    {
        $this->clearMessages();

        if (!$this->reschedulingReservationId || !$this->selectedNewSlotId) {
            $this->errorMessage = 'Please select a new time slot.';
            return;
        }

        try {
            $reservation = Reservation::where('user_id', auth()->id())
                ->findOrFail($this->reschedulingReservationId);
            $service->reschedule($reservation, $this->selectedNewSlotId);
            $this->successMessage = 'Reservation rescheduled successfully!';
            $this->cancelReschedule();
        } catch (\DomainException $e) {
            $this->errorMessage = $e->getMessage();
        }
    }

    private function clearMessages(): void
    {
        $this->errorMessage = '';
        $this->successMessage = '';
    }"}

