12	class ImportManager extends Component
13	{
14	    use WithFileUploads;
15	
16	    // Upload state
17	    public $file = null;
18	    public string $entity = 'services';
19	    public string $conflictStrategy = 'prefer_newest';
20	
21	    // Mapping state
22	    public ?int $activeBatchId = null;
23	    public array $sourceHeaders = [];
24	    public array $destinationFields = [];
25	    public array $fieldMapping = [];
26	
27	    // Progress state
28	    public string $step = 'upload'; // upload, mapping, processing, review, done
29	    public string $errorMessage = '';
30	    public string $successMessage = '';
31	
32	    private const CHUNK_SIZE = 50;
33	
34	    public function updatedFile(): void
35	    {
36	        $this->validate([
37	            'file' => 'required|file|max:10240|mimes:csv,txt,json',
38	        ]);
39	    }
40	
41	    public function upload(ImportExportService $service): void
42	    {
43	        $this->validate([
44	            'file' => 'required|file|max:10240|mimes:csv,txt,json',
45	            'entity' => 'required|in:services,users',
46	        ]);
47	
48	        $this->errorMessage = '';
49	
50	        $ext = $this->file->getClientOriginalExtension();
51	        $format = in_array($ext, ['json']) ? 'json' : 'csv';
52	
53	        $path = $this->file->store('imports', 'local');
54	        $fullPath = storage_path('app/' . $path);
55	
56	        try {
57	            $this->sourceHeaders = $service->detectHeaders($fullPath, $format);
58	            $this->destinationFields = $service->getDestinationFields($this->entity);
59	
60	            if (empty($this->sourceHeaders)) {
61	                $this->errorMessage = 'File appears to be empty or has no recognizable headers.';
62	                return;
63	            }
64	
65	            // Auto-map matching field names
66	            $this->fieldMapping = [];
67	            foreach ($this->sourceHeaders as $header) {
68	                $normalized = strtolower(str_replace([' ', '-'], '_', $header));
69	                if (in_array($normalized, $this->destinationFields)) {
70	                    $this->fieldMapping[$header] = $normalized;
71	                } else {
72	                    $this->fieldMapping[$header] = '';
73	                }
74	            }
75	
76	            // Create batch record
77	            $rows = $service->parseFile($fullPath, $format);
78	
79	            $batch = ImportBatch::create([
80	                'user_id' => auth()->id(),
81	                'entity' => $this->entity,
82	                'filename' => $this->file->getClientOriginalName(),
83	                'format' => $format,
84	                'status' => 'mapping',
85	                'total_rows' => count($rows),
86	                'conflict_strategy' => $this->conflictStrategy,
87	            ]);
88	
89	            $this->activeBatchId = $batch->id;
90	            $this->step = 'mapping';
91	        } catch (\Exception $e) {
92	            $this->errorMessage = 'Failed to parse file: ' . $e->getMessage();
93	        }
94	    }
95	
96	    public function startProcessing(ImportExportService $service): void
97	    {
98	        $batch = ImportBatch::findOrFail($this->activeBatchId);
99	
100	        // Require at least one mapped field
101	        $activeMappings = array_filter($this->fieldMapping);
102	        if (empty($activeMappings)) {
103	            $this->errorMessage = 'Please map at least one field.';
104	            return;
105	        }
106	
107	        $batch->update([
108	            'field_mapping' => $this->fieldMapping,
109	            'conflict_strategy' => $this->conflictStrategy,
110	            'status' => 'processing',
111	        ]);
112	
113	        // Parse and dispatch in chunks
114	        $path = storage_path('app/imports/' . basename($batch->filename));
115	
116	        // Re-read from stored path
117	        $storedFiles = glob(storage_path('app/imports/*'));
118	        $latestFile = end($storedFiles);
119	
120	        if (!$latestFile) {
121	            $this->errorMessage = 'Import file not found.';
122	            return;
123	        }
124	
125	        $rows = $service->parseFile($latestFile, $batch->format);
126	        $chunks = array_chunk($rows, self::CHUNK_SIZE);
127	
128	        $startIndex = 0;
129	        foreach ($chunks as $chunk) {
130	            ProcessImportChunk::dispatch($batch->id, $chunk, $startIndex);
131	            $startIndex += count($chunk);
132	        }
133	
134	        $this->step = 'processing';
135	        $this->successMessage = "Import started! Processing {$batch->total_rows} rows in " . count($chunks) . " chunk(s).";
136	    }
137	
138	    public function refreshProgress(): void
139	    {
140	        // Livewire will re-render with fresh batch data
141	    }
142	
143	    public function resolveConflict(int $conflictId, string $resolution, ImportExportService $service): void
144	    {
145	        $conflict = ImportConflict::findOrFail($conflictId);
146	        $service->resolveConflict($conflict, $resolution);
147	    }
148	
149	    public function finishReview(): void
150	    {
151	        $batch = ImportBatch::findOrFail($this->activeBatchId);
152	
153	        if ($batch->unresolvedConflicts()->count() > 0) {
154	            $this->errorMessage = 'Please resolve all conflicts before finishing.';
155	            return;
156	        }
157	
158	        $batch->update([
159	            'status' => 'completed',
160	            'completed_at' => now(),
161	        ]);
162	
163	        $this->step = 'done';
164	    }
165	
166	    public function startNew(): void
167	    {
168	        $this->reset();
169	        $this->step = 'upload';
170	    }
171	
172	    public function isStepComplete(string $checkStep): bool
173	    {
174	        $order = ['upload', 'mapping', 'processing', 'review', 'done'];
175	        $currentIndex = array_search($this->step, $order);
176	        $checkIndex = array_search($checkStep, $order);
177	
178	        return $checkIndex < $currentIndex;
179	    }
180	
181	    public function render()
182	    {
183	        $batch = $this->activeBatchId ? ImportBatch::with('conflicts')->find($this->activeBatchId) : null;
184	
185	        // Auto-advance from processing to review/done
186	        if ($batch && $this->step === 'processing') {
187	            if ($batch->isComplete() || $batch->status === 'pending_review') {
188	                $this->step = $batch->unresolvedConflicts()->count() > 0 ? 'review' : 'done';
189	            }
190	        }
191	
192	        return view('livewire.admin.import-manager', [
193	            'batch' => $batch,
194	            'conflicts' => $batch?->unresolvedConflicts()->get() ?? collect(),
195	        ])->layout('components.layouts.app', ['title' => 'Import Data']);
196	    }
197	}
