17	    private const FREE_CANCEL_HOURS = 24;
18	    private const CANCEL_FEE = 25.00;
19	    private const CANCEL_POINTS = 50;
20	    private const PENALTY_MODE = 'fee'; // 'fee' or 'points' - only one deduction path per penalty
21	    private const NO_SHOW_THRESHOLD = 2;
22	    private const NO_SHOW_WINDOW_DAYS = 60;
