27	    public function createReservation(User $user, int $timeSlotId): Reservation
28	    {
29	        if (!$user->isLearner()) {
30	            throw new \DomainException('Only learners can create reservations.');
31	        }
32	
33	        if ($user->isBookingFrozen()) {
34	            throw new \DomainException('Your booking privileges are frozen until ' . $user->booking_frozen_until->format('M d, Y'));
35	        }
36	
37	        return DB::transaction(function () use ($user, $timeSlotId) {
38	            // Pessimistic lock on the time slot
39	            $slot = TimeSlot::lockForUpdate()->findOrFail($timeSlotId);
40	
41	            if (!$slot->hasAvailability()) {
42	                throw new \DomainException('This time slot is no longer available.');
43	            }
44	
45	            if (!$slot->isFuture()) {
46	                throw new \DomainException('Cannot book a past time slot.');
47	            }
48	
49	            // Check for existing reservation on same slot
50	            $existing = Reservation::where('user_id', $user->id)
51	                ->where('time_slot_id', $timeSlotId)
52	                ->whereNotIn('status', [
53	                    ReservationStatus::Cancelled->value,
54	                    ReservationStatus::NoShow->value,
55	                ])
56	                ->exists();
57	
58	            if ($existing) {
59	                throw new \DomainException('You already have a reservation for this time slot.');
60	            }
61	
62	            $reservation = Reservation::create([
63	                'user_id' => $user->id,
64	                'service_id' => $slot->service_id,
65	                'time_slot_id' => $timeSlotId,
66	                'status' => ReservationStatus::Pending,
67	                'expires_at' => now()->addMinutes(self::EXPIRY_MINUTES),
68	            ]);
69	
70	            $slot->increment('booked_count');
71	
72	            // Dispatch expiry job
73	            ExpireUnconfirmedReservation::dispatch($reservation->id)
74	                ->delay(now()->addMinutes(self::EXPIRY_MINUTES));
75	
76	            $this->audit->log(AuditAction::ReservationCreated, $user->id, [
77	                'reservation_id' => $reservation->id,
78	                'time_slot_id' => $timeSlotId,
79	            ]);
80	
81	            return $reservation;
82	        });
83	    }
