108	    public function cancel(Reservation $reservation, ?string $reason = null): Reservation
109	    {
110	        if (!$reservation->canCancel()) {
111	            throw new \DomainException('This reservation cannot be cancelled.');
112	        }
113	
114	        return DB::transaction(function () use ($reservation, $reason) {
115	            $reservation->update([
