236	    public function processNoShows(): int
237	    {
238	        $processed = 0;
239	
240	        // Find all confirmed reservations where the check-in window has closed
241	        $noShows = Reservation::where('status', ReservationStatus::Confirmed)
242	            ->whereHas('timeSlot', function ($q) {
243	                $q->where('start_time', '<', now()->subMinutes(10));
244	            })
245	            ->get();
246	
247	        foreach ($noShows as $reservation) {
248	            DB::transaction(function () use ($reservation) {
249	                $reservation->update(['status' => ReservationStatus::NoShow]);
250	
251	                Penalty::create([
