253	                    'reservation_id' => $reservation->id,
254	                    'type' => 'no_show',
255	                    'fee_amount' => 0,
256	                    'points_deducted' => 0,
257	                    'reason' => 'Did not check in within the allowed window.',
258	                    'created_at' => now(),
259	                ]);
260	            });
261	
262	            $processed++;
263	        }
264	
265	        // Check breach thresholds and freeze accounts
266	        $this->evaluateFreezes();
267	
268	        return $processed;
