271	    private function evaluateFreezes(): void
272	    {
273	        $windowStart = now()->subDays(self::NO_SHOW_WINDOW_DAYS);
274	
275	        $breachCounts = Penalty::where('type', 'no_show')
276	            ->where('created_at', '>=', $windowStart)
277	            ->selectRaw('user_id, count(*) as breach_count')
278	            ->groupBy('user_id')
279	            ->having('breach_count', '>=', self::NO_SHOW_THRESHOLD)
280	            ->pluck('breach_count', 'user_id');
281	
282	        foreach ($breachCounts as $userId => $count) {
283	            $user = User::find($userId);
284	            if ($user && !$user->isBookingFrozen()) {
285	                $user->update([
286	                    'booking_frozen_until' => now()->addDays(self::FREEZE_DAYS),
287	                ]);
