3	namespace App\Services;
4	
5	use App\Enums\AuditAction;
6	use App\Enums\ReservationStatus;
7	use App\Jobs\ExpireUnconfirmedReservation;
8	use App\Models\Penalty;
9	use App\Models\Reservation;
10	use App\Models\TimeSlot;
11	use App\Models\User;
12	use Illuminate\Support\Facades\DB;
13	
14	class ReservationService
15	{
16	    private const EXPIRY_MINUTES = 30;
17	    private const FREE_CANCEL_HOURS = 24;
18	    private const CANCEL_FEE = 25.00;
19	    private const CANCEL_POINTS = 50;
20	    private const PENALTY_MODE = 'fee'; // 'fee' or 'points' - only one deduction path per penalty
21	    private const NO_SHOW_THRESHOLD = 2;
22	    private const NO_SHOW_WINDOW_DAYS = 60;
23	    private const FREEZE_DAYS = 7;
24	
25	    public function __construct(private AuditService $audit) {}
26	
27	    public function createReservation(User $user, int $timeSlotId): Reservation
28	    {
29	        if (!$user->isLearner()) {
30	            throw new \DomainException('Only learners can create reservations.');
31	        }
32	
33	        if ($user->isBookingFrozen()) {
34	            throw new \DomainException('Your booking privileges are frozen until ' . $user->booking_frozen_until->format('M d, Y'));
35	        }
36	
37	        return DB::transaction(function () use ($user, $timeSlotId) {
38	            // Pessimistic lock on the time slot
39	            $slot = TimeSlot::lockForUpdate()->findOrFail($timeSlotId);
40	
41	            if (!$slot->hasAvailability()) {
42	                throw new \DomainException('This time slot is no longer available.');
43	            }
44	
45	            if (!$slot->isFuture()) {
46	                throw new \DomainException('Cannot book a past time slot.');
47	            }
48	
49	            // Check for existing reservation on same slot
50	            $existing = Reservation::where('user_id', $user->id)
51	                ->where('time_slot_id', $timeSlotId)
52	                ->whereNotIn('status', [
53	                    ReservationStatus::Cancelled->value,
54	                    ReservationStatus::NoShow->value,
55	                ])
56	                ->exists();
57	
58	            if ($existing) {
59	                throw new \DomainException('You already have a reservation for this time slot.');
60	            }
61	
62	            $reservation = Reservation::create([
63	                'user_id' => $user->id,
64	                'service_id' => $slot->service_id,
65	                'time_slot_id' => $timeSlotId,
66	                'status' => ReservationStatus::Pending,
67	                'expires_at' => now()->addMinutes(self::EXPIRY_MINUTES),
68	            ]);
69	
70	            $slot->increment('booked_count');
71	
72	            // Dispatch expiry job
73	            ExpireUnconfirmedReservation::dispatch($reservation->id)
74	                ->delay(now()->addMinutes(self::EXPIRY_MINUTES));
75	
76	            $this->audit->log(AuditAction::ReservationCreated, $user->id, [
77	                'reservation_id' => $reservation->id,
78	                'time_slot_id' => $timeSlotId,
79	            ]);
80	
81	            return $reservation;
82	        });
83	    }
84	
85	    public function confirm(Reservation $reservation): Reservation
86	    {
87	        if ($reservation->status !== ReservationStatus::Pending) {
88	            throw new \DomainException('Only pending reservations can be confirmed.');
89	        }
90	
91	        if ($reservation->expires_at && $reservation->expires_at->isPast()) {
92	            throw new \DomainException('This reservation has expired.');
93	        }
94	
95	        $reservation->update([
96	            'status' => ReservationStatus::Confirmed,
97	            'confirmed_at' => now(),
98	            'expires_at' => null,
99	        ]);
100	
101	        $this->audit->log(AuditAction::ReservationConfirmed, $reservation->user_id, [
102	            'reservation_id' => $reservation->id,
103	        ]);
104	
105	        return $reservation;
106	    }
107	
108	    public function cancel(Reservation $reservation, ?string $reason = null): Reservation
109	    {
110	        if (!$reservation->canCancel()) {
111	            throw new \DomainException('This reservation cannot be cancelled.');
112	        }
113	
114	        return DB::transaction(function () use ($reservation, $reason) {
115	            $reservation->update([
116	                'status' => ReservationStatus::Cancelled,
117	                'cancelled_at' => now(),
118	                'cancellation_reason' => $reason,
119	            ]);
120	
121	            // Release the slot
122	            $reservation->timeSlot->decrement('booked_count');
123	
124	            // Apply late cancellation penalty (fee OR points, not both)
125	            if (!$reservation->isFreeCancellation()) {
126	                $feeAmount = self::PENALTY_MODE === 'fee' ? self::CANCEL_FEE : 0;
127	                $pointsDeducted = self::PENALTY_MODE === 'points' ? self::CANCEL_POINTS : 0;
128	                $reasonSuffix = self::PENALTY_MODE === 'fee'
129	                    ? sprintf('$%.2f fee applied.', self::CANCEL_FEE)
130	                    : sprintf('%d points deducted.', self::CANCEL_POINTS);
131	
132	                Penalty::create([
133	                    'user_id' => $reservation->user_id,
134	                    'reservation_id' => $reservation->id,
135	                    'type' => 'late_cancellation',
136	                    'fee_amount' => $feeAmount,
137	                    'points_deducted' => $pointsDeducted,
138	                    'reason' => 'Cancelled less than 24 hours before start time. ' . $reasonSuffix,
139	                    'created_at' => now(),
140	                ]);
141	            }
142	
143	            $this->audit->log(AuditAction::ReservationCancelled, $reservation->user_id, [
144	                'reservation_id' => $reservation->id,
145	                'free_cancellation' => $reservation->isFreeCancellation(),
146	            ]);
147	
148	            return $reservation;
149	        });
150	    }
151	
152	    public function reschedule(Reservation $reservation, int $newTimeSlotId): Reservation
153	    {
154	        if (!$reservation->canCancel()) {
155	            throw new \DomainException('This reservation cannot be rescheduled.');
156	        }
157	
158	        return DB::transaction(function () use ($reservation, $newTimeSlotId) {
159	            // Cancel old reservation (no penalty for reschedule)
160	            $reservation->update([
161	                'status' => ReservationStatus::Cancelled,
162	                'cancelled_at' => now(),
163	                'cancellation_reason' => 'Rescheduled',
164	            ]);
165	            $reservation->timeSlot->decrement('booked_count');
166	
167	            // Create new reservation
168	            return $this->createReservation($reservation->user, $newTimeSlotId);
169	        });
170	    }
171	
172	    public function checkIn(Reservation $reservation): Reservation
173	    {
174	        if (!$reservation->canCheckIn()) {
175	            throw new \DomainException('Check-in is not available at this time.');
176	        }
177	
178	        $isLate = $reservation->timeSlot->isLateArrival();
179	
180	        $reservation->update([
181	            'status' => $isLate
182	                ? ReservationStatus::PartialAttendance
183	                : ReservationStatus::CheckedIn,
184	            'checked_in_at' => now(),
185	        ]);
186	
187	        $this->audit->log(AuditAction::ReservationCheckedIn, $reservation->user_id, [
188	            'reservation_id' => $reservation->id,
189	            'late' => $isLate,
190	        ]);
191	
192	        return $reservation;
193	    }
194	
195	    public function checkOut(Reservation $reservation): Reservation
196	    {
197	        if (!in_array($reservation->status, [ReservationStatus::CheckedIn, ReservationStatus::PartialAttendance])) {
198	            throw new \DomainException('Cannot check out a reservation that is not checked in.');
199	        }
200	
201	        // Partial attendance cannot extend into next slot
202	        if ($reservation->status === ReservationStatus::PartialAttendance) {
203	            $reservation->update([
204	                'checked_out_at' => min(now(), $reservation->timeSlot->end_time),
205	                'status' => ReservationStatus::Completed,
206	            ]);
207	        } else {
208	            $reservation->update([
209	                'checked_out_at' => now(),
210	                'status' => ReservationStatus::Completed,
211	            ]);
212	        }
213	
214	        return $reservation;
215	    }
216	
217	    public function expireIfPending(int $reservationId): void
218	    {
219	        $reservation = Reservation::find($reservationId);
220	
221	        if (!$reservation || $reservation->status !== ReservationStatus::Pending) {
222	            return;
223	        }
224	
225	        DB::transaction(function () use ($reservation) {
226	            $reservation->update([
227	                'status' => ReservationStatus::Cancelled,
228	                'cancelled_at' => now(),
229	                'cancellation_reason' => 'Expired: not confirmed within 30 minutes.',
230	            ]);
231	
232	            $reservation->timeSlot->decrement('booked_count');
233	        });
234	    }
235	
236	    public function processNoShows(): int
237	    {
238	        $processed = 0;
239	
240	        // Find all confirmed reservations where the check-in window has closed
241	        $noShows = Reservation::where('status', ReservationStatus::Confirmed)
242	            ->whereHas('timeSlot', function ($q) {
243	                $q->where('start_time', '<', now()->subMinutes(10));
244	            })
245	            ->get();
246	
247	        foreach ($noShows as $reservation) {
248	            DB::transaction(function () use ($reservation) {
249	                $reservation->update(['status' => ReservationStatus::NoShow]);
250	
251	                Penalty::create([
252	                    'user_id' => $reservation->user_id,
253	                    'reservation_id' => $reservation->id,
254	                    'type' => 'no_show',
255	                    'fee_amount' => 0,
256	                    'points_deducted' => 0,
257	                    'reason' => 'Did not check in within the allowed window.',
258	                    'created_at' => now(),
259	                ]);
260	            });
261	
262	            $processed++;
263	        }
264	
265	        // Check breach thresholds and freeze accounts
266	        $this->evaluateFreezes();
267	
268	        return $processed;
269	    }
270	
271	    private function evaluateFreezes(): void
272	    {
273	        $windowStart = now()->subDays(self::NO_SHOW_WINDOW_DAYS);
274	
275	        $breachCounts = Penalty::where('type', 'no_show')
276	            ->where('created_at', '>=', $windowStart)
277	            ->selectRaw('user_id, count(*) as breach_count')
278	            ->groupBy('user_id')
279	            ->having('breach_count', '>=', self::NO_SHOW_THRESHOLD)
280	            ->pluck('breach_count', 'user_id');
281	
282	        foreach ($breachCounts as $userId => $count) {
283	            $user = User::find($userId);
284	            if ($user && !$user->isBookingFrozen()) {
285	                $user->update([
286	                    'booking_frozen_until' => now()->addDays(self::FREEZE_DAYS),
287	                ]);
288	
289	                $this->audit->log(AuditAction::BookingFreeze, $userId, [
290	                    'breaches' => $count,
291	                    'frozen_until' => $user->booking_frozen_until->toIso8601String(),
292	                ], 'critical');
293	            }
294	        }
295	    }
296	}
