namespace App\Livewire\Catalog;

use App\Actions\Catalog\RecordRecentView;
use App\Actions\Catalog\ToggleFavorite;
use App\Models\Service;
use App\Services\CatalogQueryService;
use App\Services\ReservationService;
use Livewire\Component;

class ServiceDetail extends Component
{
    public Service $service;
    public bool $isFavorited = false;
    public string $errorMessage = '';
    public string $successMessage = '';

    public function mount(Service $service, RecordRecentView $recordView, CatalogQueryService $catalogQuery): void
    {
        $this->service = $catalogQuery->getServiceDetail($service);

        if (auth()->check()) {
            $this->isFavorited = $catalogQuery->isUserFavorite(auth()->id(), $service->id);
            $recordView->execute(auth()->user(), $service->id);
        }
    }

    public function toggleFavorite(ToggleFavorite $action): void
    {
        $this->isFavorited = $action->execute(auth()->user(), $this->service->id);
    }

    public function bookSlot(int $timeSlotId, ReservationService $reservationService, CatalogQueryService $catalogQuery): void
    {
        $this->errorMessage = '';
        $this->successMessage = '';

        try {
            // Enforce learner-only booking policy
            $user = auth()->user();
            if (!$user->isLearner()) {
                throw new \DomainException('Only learners can book reservations.');
            }
            if ($user->isBookingFrozen()) {
                throw new \DomainException('Your booking privileges are frozen until ' . $user->booking_frozen_until->format('M d, Y'));
            }

            $reservation = $reservationService->createReservation($user, $timeSlotId);
            $this->successMessage = 'Reservation created! Please confirm within 30 minutes.';

            // Refresh available slots via query service
            $this->service = $catalogQuery->getServiceDetail($this->service);
        } catch (\DomainException $e) {
            $this->errorMessage = $e->getMessage();
        }
    }

    public function render()
    {
        return view('livewire.catalog.service-detail')
            ->layout('components.layouts.app', ['title' => $this->service->title]);
    }
}
"}

